using IntegerExtensions
using LinearAlgebra: opnorm

#
# Multiply the gates in the gate sequece produced by gridsynth pi/1024 -d 100
# and compare the result to the z-rotation gate with theta equal to pi/1024.
# The elements of the output matrix may be represented exactly and efficiently as numbers in the
# ring generated by arithmetic on elements of the input matrices: i, 1/sqrt(2)
#

# Synthesized with: gridsynth pi/1024 -d 100
gates_r1024 = "";

m = compose(gates_r1024);
theta = big(pi)/1024;
get_theta(big(m)) - theta;
rot_mat_diff = big(m) - RZ(theta);
opnorm(big(m) - RZ(theta));

nothing
